// ==================== Agents Map (Auto-Populated) ====================
export const agents = {};
allProperties.forEach(p => { if (!agents[p.agent.id]) agents[p.agent.id] = p.agent; });

// ==================== Transform & Enrich Data ====================

// Enrich allProperties with component-expected fields
allProperties.forEach(p => {
  p.media = p.images;
  p.bedrooms = p.beds;
  p.bathrooms = p.baths;
  p.area = p.sqft;
  p.trending = p.hot;
  p.agentAvatar = p.agent.avatar;
  p.rera = !!p.reraId;
  p.pricePerSqft = Math.round(p.price / p.sqft);
  p.possession = p.possessionStatus;
  p.verified = p.featured;
  p.badge = p.hot ? 'Hot Deal' : (p.featured ? 'Featured' : null);
  p.badgeType = p.hot ? 'hot' : (p.featured ? 'featured' : '');
  p.age = p.possessionStatus === 'Ready to Move' ? 'Ready' : 'New Launch';
  p.facing = ['East','North','North-East','South-East'][Math.floor(Math.random()*4)];
  p.parking = p.amenities.includes('parking') ? (p.type === 'villa' ? '2 Covered' : '1 Covered') : 'None';
  p.openHouse = p.featured && !p.hot;
  p.mediaAspectRatio = '4/3';
  p.listingStatus = p.possessionStatus;
  p.status = p.status === 'sale' ? 'For Sale' : p.status === 'rent' ? 'For Rent' : p.status;
  p.type = p.type.charAt(0).toUpperCase() + p.type.slice(1);
  p.amenities = p.amenities.map(a => {
    const amenityMap = { pool:'Pool', gym:'Gym', parking:'Parking', garden:'Garden', security:'Security', smartHome:'Smart Home' };
    return amenityMap[a] || a.charAt(0).toUpperCase() + a.slice(1);
  });
  if (p.neighborhood && !Array.isArray(p.neighborhood)) {
    p.neighborhood = [
      `Schools: ${p.neighborhood.schools}`,
      `Transit: ${p.neighborhood.transit}`,
      `Walk Score: ${p.neighborhood.walkScore}/100`,
      `Crime Rate: ${p.neighborhood.crimeRate}`,
    ];
  }
});

// Enrich propertyStories
propertyStories.forEach(s => {
  s.avatar = s.image;
  s.city = s.label;
  s.count = 3 + Math.floor(Math.random() * 4);
});

// Enrich allReels
allReels.forEach(r => {
  r.videoUrl = r.video;
  r.category = r.category.split('-').map(w => w.charAt(0).toUpperCase() + w.slice(1)).join(' ');
  const prop = allProperties.find(p => p.id === r.propertyId);
  if (prop) {
    r.bedrooms = prop.bedrooms;
    r.area = prop.area;
    r.agentAvatar = prop.agentAvatar;
  }
});

